1	// MCP server for enforcement scoring discipline.
2	// Thin wiring layer — all logic lives in scoring.js and state.js.
3	
4	import { Server } from '@modelcontextprotocol/sdk/server/index.js';
5	import { StdioServerTransport } from '@modelcontextprotocol/sdk/server/stdio.js';
6	import { ListToolsRequestSchema, CallToolRequestSchema } from '@modelcontextprotocol/sdk/types.js';
7	import { validateScoreSubmission, checkClosure } from './scoring.js';
8	import { initializeState, updateState, markChallengeUsed, saveState, loadState } from './state.js';
9	
10	const server = new Server(
11	  { name: 'chester-enforcement', version: '1.0.0' },
12	  { capabilities: { tools: {} } }
13	);
14	
15	// ── Tool Definitions ─────────────────────────────────────────────
16	
17	const TOOLS = [
18	  {
19	    name: 'initialize_interview',
20	    description: 'Initialize a new architect interview session with scoring dimensions',
21	    inputSchema: {
22	      type: 'object',
23	      properties: {
24	        type: { type: 'string', enum: ['greenfield', 'brownfield'], description: 'Interview type' },
25	        problem_statement: { type: 'string', description: 'The problem statement to evaluate' },
26	        state_file: { type: 'string', description: 'Absolute path to persist state JSON' },
27	      },
28	      required: ['type', 'problem_statement', 'state_file'],
29	    },
30	  },
31	  {
32	    name: 'submit_scores',
33	    description: 'Submit dimension scores for the current interview round',
34	    inputSchema: {
35	      type: 'object',
36	      properties: {
37	        state_file: { type: 'string', description: 'Absolute path to state JSON' },
38	        scores: {
39	          type: 'object',
40	          description: 'Scores keyed by dimension, each with score, justification, and gap',
41	          additionalProperties: {
42	            type: 'object',
43	            properties: {
44	              score: { type: 'number' },
45	              justification: { type: 'string' },
46	              gap: { type: 'string' },
47	            },
48	            required: ['score', 'justification'],
49	          },
50	        },
51	        gate_evidence: {
52	          type: 'object',
53	          description: 'Optional gate satisfaction evidence',
54	          properties: {
55	            non_goals_addressed: { type: 'boolean' },
56	            decision_boundaries_addressed: { type: 'boolean' },
57	            pressure_follow_up: {
58	              type: ['object', 'null'],
59	              properties: { original_round: { type: 'number' } },
60	            },
61	          },
62	        },
63	        challenge_used: {
64	          type: 'string',
65	          enum: ['contrarian', 'simplifier', 'ontologist'],
66	          description: 'Optional challenge mode used this round',
67	        },
68	      },
69	      required: ['state_file', 'scores'],
70	    },
71	  },
72	  {
73	    name: 'get_state',
74	    description: 'Load current interview state and check closure eligibility',
75	    inputSchema: {
76	      type: 'object',
77	      properties: {
78	        state_file: { type: 'string', description: 'Absolute path to state JSON' },
79	      },
80	      required: ['state_file'],
81	    },
82	  },
83	];
84	
85	// ── Request Handlers ─────────────────────────────────────────────
86	
87	server.setRequestHandler(ListToolsRequestSchema, async () => {
88	  return { tools: TOOLS };
89	});
90	
91	server.setRequestHandler(CallToolRequestSchema, async (request) => {
92	  const { name, arguments: args } = request.params;
93	
94	  try {
95	    switch (name) {
96	      case 'initialize_interview':
97	        return handleInitialize(args);
98	      case 'submit_scores':
99	        return handleSubmitScores(args);
100	      case 'get_state':
101	        return handleGetState(args);
102	      default:
103	        return { content: [{ type: 'text', text: `Unknown tool: ${name}` }], isError: true };
104	    }
105	  } catch (err) {
106	    return { content: [{ type: 'text', text: err.message }], isError: true };
107	  }
108	});
109	
110	// ── Tool Handlers ────────────────────────────────────────────────
111	
112	function handleInitialize({ type, problem_statement, state_file }) {
113	  const state = initializeState(type, problem_statement);
114	  saveState(state, state_file);
115	
116	  return {
117	    content: [{
118	      type: 'text',
119	      text: JSON.stringify({
120	        status: 'initialized',
121	        type,
122	        dimensions: Object.keys(state.scores),
123	        state_file,
124	      }),
125	    }],
126	  };
127	}
128	
129	function handleSubmitScores({ state_file, scores, gate_evidence, challenge_used }) {
130	  let state = loadState(state_file);
131	
132	  // Build previousScores flat map for jump detection
133	  const previousScores = {};
134	  for (const [dim, entry] of Object.entries(state.scores)) {
135	    previousScores[dim] = entry.score;
136	  }
137	
138	  // validateScoreSubmission expects an array of { dimension, score, justification, gap }
